}

/* Stagger dots for a wave effect */
.dot:nth-child(2) { animation-delay: 0.2s; }
.dot:nth-child(3) { animation-delay: 0.4s; }

/* Typewriter animation */
@keyframes typing {
  from {
    width: 0;
  }
  to {
    width: 20ch; /* 20 characters wide */
  }
}

